SELECT ethnicity_name
FROM ethnicities
WHERE population_count = (SELECT MAX(population_count) FROM ethnicities);

SELECT ethnicity_name, population_count
FROM ethnicities
ORDER BY population_count DESC;

SELECT client_id, status
FROM client_subscriptions
WHERE status = 'active';

SELECT SUM(number_of_properties) AS total_properties
FROM real_estate_companies
WHERE company_name = 'Estate Solutions';

SELECT median_income
FROM homeownership_stats
WHERE year = 2023;

SELECT COUNT(subscription_id) AS active_subscription_count
FROM client_subscriptions
WHERE client_id = 1 AND status = 'active';
